import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';

function Services() {
  const [showRegisterModal, setShowRegisterModal] = useState(false);
  
  // Registration form state
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    serviceType: 'Web Development',
    projectDetails: '',
    paymentMethod: 'Cash'
  });

  const [message, setMessage] = useState('');

  // Handle form input changes
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // Handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (formData.paymentMethod === 'Online') {
        alert("Redirecting to Secure Online Payment Gateway...");
      }

      const response = await axios.post('http://localhost:5000/api/hire', formData);
      
      if (response.status === 201) {
        setMessage("✅ Success! Your request has been saved.");
        setTimeout(() => {
          setMessage('');
          setShowRegisterModal(false);
          document.body.style.overflow = 'auto';
        }, 1500);
        
        setFormData({ 
          fullName: '', 
          email: '', 
          serviceType: 'Web Development', 
          projectDetails: '', 
          paymentMethod: 'Cash' 
        });
      }
    } catch (error) {
      console.error("Error saving data:", error);
      setMessage("❌ Error! Could not connect to the server.");
    }
  };

  // Close modal when clicking outside
  const handleOverlayClick = (e) => {
    if (e.target.classList.contains('modal-overlay')) {
      setShowRegisterModal(false);
      setMessage('');
      document.body.style.overflow = 'auto';
    }
  };

  // Function to handle Get Started click and set service type
  const handleGetStarted = (service) => {
    setFormData({ ...formData, serviceType: service });
    setShowRegisterModal(true);
    document.body.style.overflow = 'hidden';
  };

  // Handle modal close
  const handleCloseModal = () => {
    setShowRegisterModal(false);
    setMessage('');
    document.body.style.overflow = 'auto';
  };

  return (
    <div className="services-page bg-light">
      {/* 1. Header Section */}
      <section className="py-5 bg-dark text-white text-center shadow">
        <div className="container">
          <h1 className="fw-bold display-4">Our Professional Services</h1>
          <p className="lead opacity-75">High-quality digital solutions tailored for your business and academic needs.</p>
        </div>
      </section>

      {/* 2. Services Grid */}
      <section className="container py-5">
        <div className="row g-4">
          
          {/* Card 1: Web Development */}
          <div className="col-md-4">
            <div className="card h-100 border-0 shadow-sm p-4 text-center service-card">
              <div className="mb-3 text-primary"><i className="fas fa-code fa-3x"></i></div>
              <h4 className="fw-bold">Web Development</h4>
              <p className="text-muted small">Modern, responsive websites built with React, Node.js, and Bootstrap.</p>
              <button onClick={() => handleGetStarted('Web Development')} className="btn btn-outline-primary btn-sm mt-auto shadow-sm">Get Started</button>
            </div>
          </div>

          {/* Card 2: UI/UX Design */}
          <div className="col-md-4">
            <div className="card h-100 border-0 shadow-sm p-4 text-center service-card">
              <div className="mb-3 text-danger"><i className="fas fa-paint-brush fa-3x"></i></div>
              <h4 className="fw-bold">UI/UX Design</h4>
              <p className="text-muted small">Creative and user-friendly interface designs for better user experience.</p>
              <button onClick={() => handleGetStarted('UI/UX Design')} className="btn btn-outline-danger btn-sm mt-auto shadow-sm">Get Started</button>
            </div>
          </div>

          {/* Card 3: App Development */}
          <div className="col-md-4">
            <div className="card h-100 border-0 shadow-sm p-4 text-center service-card">
              <div className="mb-3 text-success"><i className="fas fa-mobile-alt fa-3x"></i></div>
              <h4 className="fw-bold">App Development</h4>
              <p className="text-muted small">Custom Android and iOS applications with seamless performance.</p>
              <button onClick={() => handleGetStarted('App Development')} className="btn btn-outline-success btn-sm mt-auto shadow-sm">Get Started</button>
            </div>
          </div>

          {/* Card 4: Assignment Support */}
          <div className="col-md-4">
            <div className="card h-100 border-0 shadow-sm p-4 text-center service-card">
              <div className="mb-3 text-warning"><i className="fas fa-book-open fa-3x"></i></div>
              <h4 className="fw-bold">Assignment Support</h4>
              <p className="text-muted small">Expert help for students to complete their academic projects on time.</p>
              <button onClick={() => handleGetStarted('Assignment Support')} className="btn btn-outline-warning btn-sm mt-auto shadow-sm">Get Started</button>
            </div>
          </div>

          {/* Card 5: Presentation Design */}
          <div className="col-md-4">
            <div className="card h-100 border-0 shadow-sm p-4 text-center service-card">
              <div className="mb-3 text-info"><i className="fas fa-file-powerpoint fa-3x"></i></div>
              <h4 className="fw-bold">PPT Design</h4>
              <p className="text-muted small">Professional PowerPoint presentations for business and college use.</p>
              <button onClick={() => handleGetStarted('PPT Design')} className="btn btn-outline-info btn-sm mt-auto shadow-sm">Get Started</button>
            </div>
          </div>

          {/* Card 6: Report Writing */}
          <div className="col-md-4">
            <div className="card h-100 border-0 shadow-sm p-4 text-center service-card">
              <div className="mb-3 text-secondary"><i className="fas fa-file-alt fa-3x"></i></div>
              <h4 className="fw-bold">Report Writing</h4>
              <p className="text-muted small">Detailed technical and business report writing with proper documentation.</p>
              <button onClick={() => handleGetStarted('Report Writing')} className="btn btn-outline-secondary btn-sm mt-auto shadow-sm">Get Started</button>
            </div>
          </div>

        </div>
      </section>

      {/* 3. Working Process Section */}
      <section className="py-5 bg-white border-top">
        <div className="container">
          <h2 className="text-center fw-bold mb-5">How It Works?</h2>
          <div className="row text-center g-4">
            <div className="col-md-3">
              <div className="process-step">
                <div className="badge bg-primary rounded-circle mb-3 p-3 fs-5 shadow-sm">01</div>
                <h5 className="fw-bold">Consultation</h5>
                <p className="text-muted small">We discuss your ideas and project requirements.</p>
              </div>
            </div>
            <div className="col-md-3">
              <div className="process-step">
                <div className="badge bg-primary rounded-circle mb-3 p-3 fs-5 shadow-sm">02</div>
                <h5 className="fw-bold">Strategy</h5>
                <p className="text-muted small">We create a perfect timeline and design plan.</p>
              </div>
            </div>
            <div className="col-md-3">
              <div className="process-step">
                <div className="badge bg-primary rounded-circle mb-3 p-3 fs-5 shadow-sm">03</div>
                <h5 className="fw-bold">Development</h5>
                <p className="text-muted small">Our experts build your product with quality code.</p>
              </div>
            </div>
            <div className="col-md-3">
              <div className="process-step">
                <div className="badge bg-primary rounded-circle mb-3 p-3 fs-5 shadow-sm">04</div>
                <h5 className="fw-bold">Delivery</h5>
                <p className="text-muted small">Your project is delivered on time with support.</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Registration Modal/Popup - Smaller Compact Size */}
      {showRegisterModal && (
        <div className="modal-overlay" onClick={handleOverlayClick} style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.7)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 9999,
          padding: '10px',
          backdropFilter: 'blur(3px)'
        }}>
          <div className="modal-content" style={{
            backgroundColor: 'white',
            borderRadius: '16px',
            maxWidth: '550px',
            width: '100%',
            position: 'relative',
            animation: 'modalFadeIn 0.3s ease-out',
            boxShadow: '0 20px 40px -12px rgba(0, 0, 0, 0.3)',
            overflow: 'hidden'
          }}>
            {/* Modal Header - Compact */}
            <div style={{
              padding: '16px 20px',
              background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              color: 'white'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <h3 className="fw-bold mb-0" style={{ fontSize: '1.2rem' }}>Hire a Freelancer</h3>
                  <p style={{ opacity: 0.9, margin: '2px 0 0', fontSize: '0.8rem' }}>Fill in your details</p>
                </div>
                <button 
                  onClick={handleCloseModal}
                  style={{
                    background: 'rgba(255,255,255,0.2)',
                    border: 'none',
                    color: 'white',
                    fontSize: '20px',
                    cursor: 'pointer',
                    width: '32px',
                    height: '32px',
                    borderRadius: '50%',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    transition: 'all 0.3s'
                  }}
                  onMouseEnter={(e) => e.target.style.background = 'rgba(255,255,255,0.3)'}
                  onMouseLeave={(e) => e.target.style.background = 'rgba(255,255,255,0.2)'}
                >
                  ×
                </button>
              </div>
            </div>

            {/* Modal Body - Compact Form */}
            <div style={{ padding: '20px' }}>
              {message && (
                <div style={{
                  padding: '8px 12px',
                  borderRadius: '6px',
                  marginBottom: '15px',
                  backgroundColor: message.includes('Success') ? '#d4edda' : '#f8d7da',
                  color: message.includes('Success') ? '#155724' : '#721c24',
                  border: message.includes('Success') ? '1px solid #c3e6cb' : '1px solid #f5c6cb',
                  fontSize: '0.85rem',
                  textAlign: 'center'
                }}>
                  {message}
                </div>
              )}

              <form onSubmit={handleSubmit}>
                {/* First Row: Full Name and Email */}
                <div style={{ 
                  display: 'grid', 
                  gridTemplateColumns: '1fr 1fr', 
                  gap: '12px',
                  marginBottom: '12px'
                }}>
                  {/* Full Name */}
                  <div>
                    <label style={{ 
                      display: 'block', 
                      marginBottom: '4px', 
                      fontWeight: '500',
                      fontSize: '0.8rem',
                      color: '#4a5568'
                    }}>
                      Full Name <span style={{ color: '#e53e3e' }}>*</span>
                    </label>
                    <input 
                      type="text" 
                      name="fullName" 
                      value={formData.fullName} 
                      onChange={handleChange} 
                      required 
                      style={{
                        width: '100%',
                        padding: '8px 10px',
                        borderRadius: '6px',
                        border: '1px solid #e2e8f0',
                        fontSize: '0.85rem',
                        transition: 'all 0.2s',
                        outline: 'none'
                      }}
                      onFocus={(e) => e.target.style.borderColor = '#667eea'}
                      onBlur={(e) => e.target.style.borderColor = '#e2e8f0'}
                      placeholder="John Doe"
                    />
                  </div>

                  {/* Email */}
                  <div>
                    <label style={{ 
                      display: 'block', 
                      marginBottom: '4px', 
                      fontWeight: '500',
                      fontSize: '0.8rem',
                      color: '#4a5568'
                    }}>
                      Email <span style={{ color: '#e53e3e' }}>*</span>
                    </label>
                    <input 
                      type="email" 
                      name="email" 
                      value={formData.email} 
                      onChange={handleChange} 
                      required 
                      style={{
                        width: '100%',
                        padding: '8px 10px',
                        borderRadius: '6px',
                        border: '1px solid #e2e8f0',
                        fontSize: '0.85rem',
                        transition: 'all 0.2s',
                        outline: 'none'
                      }}
                      onFocus={(e) => e.target.style.borderColor = '#667eea'}
                      onBlur={(e) => e.target.style.borderColor = '#e2e8f0'}
                      placeholder="john@example.com"
                    />
                  </div>
                </div>

                {/* Second Row: Service Type and Payment Method */}
                <div style={{ 
                  display: 'grid', 
                  gridTemplateColumns: '1fr 1fr', 
                  gap: '12px',
                  marginBottom: '12px'
                }}>
                  {/* Service Type */}
                  <div>
                    <label style={{ 
                      display: 'block', 
                      marginBottom: '4px', 
                      fontWeight: '500',
                      fontSize: '0.8rem',
                      color: '#4a5568'
                    }}>
                      Service
                    </label>
                    <div style={{
                      padding: '8px 10px',
                      borderRadius: '6px',
                      backgroundColor: '#f7fafc',
                      border: '1px solid #e2e8f0',
                      fontSize: '0.85rem',
                      fontWeight: '500',
                      color: '#667eea',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '6px',
                      height: '36px'
                    }}>
                      <span style={{
                        width: '6px',
                        height: '6px',
                        backgroundColor: '#667eea',
                        borderRadius: '50%',
                        display: 'inline-block'
                      }}></span>
                      {formData.serviceType}
                    </div>
                  </div>

                  {/* Payment Method */}
                  <div>
                    <label style={{ 
                      display: 'block', 
                      marginBottom: '4px', 
                      fontWeight: '500',
                      fontSize: '0.8rem',
                      color: '#4a5568'
                    }}>
                      Payment <span style={{ color: '#e53e3e' }}>*</span>
                    </label>
                    <select 
                      name="paymentMethod" 
                      value={formData.paymentMethod} 
                      onChange={handleChange}
                      style={{
                        width: '100%',
                        padding: '8px 10px',
                        borderRadius: '6px',
                        border: '1px solid #e2e8f0',
                        fontSize: '0.85rem',
                        transition: 'all 0.2s',
                        outline: 'none',
                        backgroundColor: 'white',
                        cursor: 'pointer',
                        height: '36px'
                      }}
                      onFocus={(e) => e.target.style.borderColor = '#667eea'}
                      onBlur={(e) => e.target.style.borderColor = '#e2e8f0'}
                    >
                      <option value="Cash">Cash / Direct</option>
                      <option value="Online">Online (UPI/Card)</option>
                    </select>
                  </div>
                </div>

                {/* Payment Note */}
                <div style={{ 
                  marginBottom: '15px',
                  fontSize: '0.7rem',
                  color: '#a0aec0',
                  textAlign: 'right'
                }}>
                  *Online payment is simulated
                </div>

                {/* Third Row: Project Details */}
                <div style={{ marginBottom: '20px' }}>
                  <label style={{ 
                    display: 'block', 
                    marginBottom: '4px', 
                    fontWeight: '500',
                    fontSize: '0.8rem',
                    color: '#4a5568'
                  }}>
                    Project Details <span style={{ color: '#e53e3e' }}>*</span>
                  </label>
                  <textarea 
                    name="projectDetails" 
                    rows="3" 
                    value={formData.projectDetails} 
                    onChange={handleChange} 
                    required
                    placeholder="Describe your project requirements..."
                    style={{
                      width: '100%',
                      padding: '8px 10px',
                      borderRadius: '6px',
                      border: '1px solid #e2e8f0',
                      fontSize: '0.85rem',
                      transition: 'all 0.2s',
                      outline: 'none',
                      resize: 'vertical',
                      fontFamily: 'inherit'
                    }}
                    onFocus={(e) => e.target.style.borderColor = '#667eea'}
                    onBlur={(e) => e.target.style.borderColor = '#e2e8f0'}
                  ></textarea>
                </div>

                {/* Buttons */}
                <div style={{ display: 'flex', gap: '8px' }}>
                  <button 
                    type="submit" 
                    style={{
                      flex: 1,
                      padding: '10px',
                      borderRadius: '6px',
                      border: 'none',
                      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                      color: 'white',
                      fontWeight: '500',
                      fontSize: '0.85rem',
                      cursor: 'pointer',
                      transition: 'all 0.2s',
                      boxShadow: '0 2px 4px rgba(102, 126, 234, 0.2)'
                    }}
                    onMouseEnter={(e) => e.target.style.transform = 'translateY(-1px)'}
                    onMouseLeave={(e) => e.target.style.transform = 'translateY(0)'}
                  >
                    Send Request
                  </button>
                  <button 
                    type="button" 
                    onClick={handleCloseModal}
                    style={{
                      padding: '10px 16px',
                      borderRadius: '6px',
                      border: '1px solid #e2e8f0',
                      background: 'white',
                      color: '#4a5568',
                      fontWeight: '500',
                      fontSize: '0.85rem',
                      cursor: 'pointer',
                      transition: 'all 0.2s'
                    }}
                    onMouseEnter={(e) => {
                      e.target.style.borderColor = '#cbd5e0';
                      e.target.style.background = '#f7fafc';
                    }}
                    onMouseLeave={(e) => {
                      e.target.style.borderColor = '#e2e8f0';
                      e.target.style.background = 'white';
                    }}
                  >
                    Cancel
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Hover Effects CSS */}
      <style>{`
        .service-card { 
          transition: 0.3s ease; 
          cursor: pointer; 
        }
        .service-card:hover { 
          transform: translateY(-10px); 
          box-shadow: 0 10px 20px rgba(0,0,0,0.1) !important; 
        }
        .process-step { 
          padding: 20px; 
        }
        
        @keyframes modalFadeIn {
          from {
            opacity: 0;
            transform: scale(0.95) translateY(-10px);
          }
          to {
            opacity: 1;
            transform: scale(1) translateY(0);
          }
        }
        
        body.modal-open {
          overflow: hidden;
        }
        
        @media (max-width: 500px) {
          div[style*="gridTemplateColumns: '1fr 1fr'"] {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  );
}

export default Services;
